# Navigation/boilerplate to strip
nav_pattern = r'(PropertiesServicesAbout MPSGet in touchManage my property.*?Get in touchManage my property)'
footer_pattern = r'(QuicklinksPropertiesOur ServicesAbout MPSContact Us.*?Made by MPS)'

def clean_text(text):
    # Remove navigation
    text = re.sub(nav_pattern, '', text, flags=re.DOTALL)
    # Remove footer
    text = re.sub(footer_pattern, '', text, flags=re.DOTALL)
    # Remove phone/email patterns
    text = re.sub(r'\+212\s*\d+\s*\d+\s*\d+\s*\d+\s*\d+', '', text)
    text = re.sub(r'\S+@\S+\.\S+', '', text)
    # Remove extra whitespace
    text = re.sub(r'\s+', ' ', text).strip()
    return text

print("=" * 70)
print("WORD COUNT ANALYSIS (Main Content Only)")
print("=" * 70)

for name, text in pages.items():
    cleaned = clean_text(text)
    words = len(cleaned.split())
    print(f"{name:15} : {words:5} words")

print("\n" + "=" * 70)
print("KEYWORD ANALYSIS")
print("=" * 70)

primary_keywords = ['property management', 'marrakech', 'villa', 'riad', 'airbnb', 'concierge', 'luxury']

for name, text in pages.items():
    text_lower = text.lower()
    print(f"\n--- {name} ---")
    for kw in primary_keywords:
        count = text_lower.count(kw)
        if count > 0:
            print(f"  '{kw}': {count} occurrences")

print("\n" + "=" * 70)
print("INTERNAL LINK ANALYSIS")
print("=" * 70)

internal_paths = ['/properties/', '/about-mps/', '/contact-us/', '/meeting-and-events/',
                  '/frequently-asked-questions/', '/locations/', '/our-latest-storey/']

for name, text in pages.items():
    links = []
    for path in internal_paths:
        if path in text:
            links.append(path)
    print(f"{name:15} : {len(links)} internal links -> {links}")

print("\n" + "=" * 70)
print("READABILITY ESTIMATES")
print("=" * 70)

for name, text in pages.items():
    cleaned = clean_text(text)
    words = cleaned.split()
    sentences = re.split(r'[.!?]+', cleaned)
    sentences = [s.strip() for s in sentences if s.strip()]

    avg_words_per_sentence = len(words) / max(len(sentences), 1)
    # Flesch-Kincaid approximation
    syllables = sum(max(1, len(w) * 0.5) for w in words)
    fk_grade = 0.39 * avg_words_per_sentence + 11.8 * (syllables / max(len(words), 1)) - 15.59
    fk_grade = max(1, min(16, fk_grade))

    print(f"{name:15} : Avg sentence length: {avg_words_per_sentence:.1f} words | Est. FK Grade: {fk_grade:.1f}")
